CREATE PROPERTY GRAPH knowledge_graph
  VERTEX TABLES (kg_nodes KEY (node_id) PROPERTIES (doc_id, name))
  EDGE TABLES (kg_edges KEY (edge_id)
                        SOURCE      KEY (src_id) REFERENCES kg_nodes (node_id)
                        DESTINATION KEY (dst_id) REFERENCES kg_nodes (node_id)
                        PROPERTIES (rel_type));

WITH
semantic_matches AS (
  -- Vector similarity search (literal probe vector — bind one in production)
  SELECT doc_id, chunk_text,
         VECTOR_DISTANCE(embedding,
                         TO_VECTOR('[0.10, 0.20, 0.30, 0.40]'),
                         COSINE) AS score
  FROM   knowledge_base
  ORDER  BY score
  FETCH  FIRST 20 ROWS ONLY
),
graph_context AS (
  -- Graph traversal (SQL/PGQ). GRAPH_TABLE projects the doc_id alongside
  -- the matched entities so the join can stay outside the operator.
  SELECT g.entity, g.related, g.rel_type
  FROM   GRAPH_TABLE(knowledge_graph
           MATCH (v1) -[e]-> (v2)
           COLUMNS (v1.doc_id  AS source_doc,
                    v1.name    AS entity,
                    v2.name    AS related,
                    e.rel_type AS rel_type)
         ) g
  JOIN   semantic_matches s ON s.doc_id = g.source_doc
),
enriched AS (
  -- Relational metadata
  SELECT s.doc_id, s.score, d.title, d.author
  FROM   semantic_matches s
  JOIN   documents d ON d.id = s.doc_id
)
SELECT JSON_OBJECT(
  'results' VALUE (
    SELECT JSON_ARRAYAGG(
      JSON_OBJECT(
        'title'     VALUE e.title,
        'score'     VALUE ROUND(e.score, 4),
        'relations' VALUE (
          SELECT JSON_ARRAYAGG(
            JSON_OBJECT('entity'  VALUE g.entity,
                        'related' VALUE g.related,
                        'type'    VALUE g.rel_type
                        RETURNING JSON)
            RETURNING JSON
          )
          FROM graph_context g
        )
        RETURNING JSON
      ) ORDER BY e.score
      RETURNING JSON
    ) FROM enriched e
  )
  RETURNING JSON
) AS rag_context
FROM DUAL;

CREATE INDEX idx_order_status ON orders (
  JSON_VALUE(order_doc, '$.status' RETURNING VARCHAR2(20) ERROR ON ERROR)
);

-- Composite index across multiple JSON fields
CREATE INDEX idx_order_cust_date ON orders (
  JSON_VALUE(order_doc, '$.customer.name' RETURNING VARCHAR2(100)),
  JSON_VALUE(order_doc, '$.orderDate' RETURNING DATE)
);

CREATE INDEX idx_order_customer ON orders o (
  o.order_doc.customer.string()
);

-- Index for string comparisons: WHERE amount.string() = '100.00'
CREATE INDEX idx_amount_str ON orders o (o.order_doc.amount.string());

-- Index for numeric comparisons: WHERE amount.number() > 100
CREATE INDEX idx_amount_num ON orders o (o.order_doc.amount.number());

-- Transactional (default)
CREATE SEARCH INDEX idx_orders_search ON orders (order_doc) FOR JSON
  PARAMETERS ('SYNC (ON COMMIT)');

-- Or periodic, if you'd rather trade freshness for write throughput
CREATE SEARCH INDEX idx_orders_search ON orders (order_doc) FOR JSON
  PARAMETERS ('SYNC (EVERY "FREQ=SECONDLY; INTERVAL=1")');

CREATE MULTIVALUE INDEX idx_order_tags ON orders o (
  o.order_doc.tags.string()
);

-- This query uses the multivalue index
SELECT * FROM orders o
WHERE  JSON_EXISTS(o.order_doc, '$.tags[*]?(@.string() == "wholesale")');

-- Tags queried as strings
CREATE MULTIVALUE INDEX idx_order_tags ON orders o (o.order_doc.tags.string());

-- Numeric IDs queried as numbers
CREATE MULTIVALUE INDEX idx_order_ids_num ON orders o (o.order_doc.relatedIds.number());

-- Both "123" and 123 are indexed as the string "123"
CREATE MULTIVALUE INDEX idx_order_tags ON orders o (o.order_doc.tags.string());

-- Both "123" and 123 are indexed as the number 123
CREATE MULTIVALUE INDEX idx_order_tags_num ON orders o (o.order_doc.tags.number());

-- Schema-version routing: each row contributes to exactly one of these
CREATE INDEX idx_amount_v1 ON orders (
  CASE
    WHEN JSON_VALUE(order_doc, '$.schemaVersion') = '1'
      THEN JSON_VALUE(order_doc, '$.amount' RETURNING VARCHAR2(30))
  END
);

CREATE INDEX idx_amount_v2 ON orders (
  CASE
    WHEN JSON_VALUE(order_doc, '$.schemaVersion') = '2'
      THEN JSON_VALUE(order_doc, '$.amount' RETURNING NUMBER)
  END
);

-- One table, multiple entity types, write-path-isolated indexes
CREATE INDEX idx_customer_name ON entities (
  CASE
    WHEN JSON_VALUE(doc, '$.entityType') = 'customer'
      THEN JSON_VALUE(doc, '$.companyName' RETURNING VARCHAR2(200))
  END
);

CREATE INDEX idx_product_sku ON entities (
  CASE
    WHEN JSON_VALUE(doc, '$.entityType') = 'product'
      THEN JSON_VALUE(doc, '$.sku' RETURNING VARCHAR2(50))
  END
);

CREATE INDEX idx_invoice_number ON entities (
  CASE
    WHEN JSON_VALUE(doc, '$.entityType') = 'invoice'
      THEN JSON_VALUE(doc, '$.invoiceNo' RETURNING NUMBER)
  END
);

CREATE TABLE validated_orders (
  id   NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  data JSON VALIDATE '{
    "type": "object",
    "properties": {
      "orderId":  {"type": "number"},
      "customer": {"type": "string"},
      "items":    {"type": "array", "items": {
        "type": "object",
        "required": ["product", "quantity"]
      } }
    },
    "required": ["orderId", "customer", "items"]
  }'
);

CREATE TABLE dv_orders (
  order_id      NUMBER PRIMARY KEY,
  customer_name VARCHAR2(200) NOT NULL
);

CREATE TABLE dv_order_items (
  item_id      NUMBER PRIMARY KEY,
  order_id     NUMBER REFERENCES dv_orders ON DELETE CASCADE,
  product_name VARCHAR2(200),
  quantity     NUMBER,
  unit_price   NUMBER(12, 2)
);

