CREATE OR REPLACE JSON RELATIONAL DUALITY VIEW order_dv AS
  SELECT JSON {
    '_id'      : o.order_id,         -- root PK must be projected
    'customer' : o.customer_name,
    'items'    : [ SELECT JSON {
                     '_id'      : i.item_id,   -- nested PK must also be projected
                     'product'  : i.product_name,
                     'quantity' : i.quantity,
                     'price'    : i.unit_price
                   }
                   FROM dv_order_items i WITH UPDATE
                   WHERE i.order_id = o.order_id ]
  }
  FROM dv_orders o WITH INSERT UPDATE DELETE;
